import React, { Component } from "react";
import "./Queues.css";
 
// Import React Table
import ReactTable from "react-table";
import "react-table/react-table.css";

class FinishedJobQueue extends Component {
    render() {
      return (
        <div className="">
          <ReactTable 
            resizable={false}
            // sortable={false}
            showPageSizeOptions={false}
            data={this.props.data}
            columns={[
                {
                  Header: "Job #",
                  accessor: "JobNumber",
                  minWidth: 50
                },
                {
                  Header: "Memory (M)",
                  id: "memory",
                  accessor: "Memory",
                  minWidth: 90
                },
                {
                    Header: "Finished (F)",
                    id: "TimeFinished",
                    accessor: d => (d.FinishTime),
                    minWidth: 100
                },
                {
                  Header: "Run Time (R)",
                  id: "RunTime",
                  accessor: d => (d.NeededRunTime),
                  minWidth: 100
                },
                {
                  Header: "Wait (W)",
                  id: "WaitTime",
                  accessor: d => (d.FinishTime - d.ArrivalTime - d.NeededRunTime),
                  minWidth: 75
                },
                {
                  Header: "Arrival (A)",
                  id: "Arrival",
                  accessor: d => (d.ArrivalTime),
                  minWidth: 100
                },
                {
                  Header: "Burst (B)",
                  id: "BurstIO",
                  accessor: d => (d.NeededIOBurstTime),
                  minWidth: 80
                }
              ]
            }
        //     defaultSorted={[
        //     {
        //       id: "arrivalTime",
        //       desc: false
        //     }
        //   ]}
          defaultPageSize={10}
          style={{
            height: "420px" // This will force the table body to overflow and scroll, since there is not enough room
          }}
          className="-striped -highlight"
        />
      </div>
      );
    }
  }

  export default FinishedJobQueue;


